import{i as r}from"./theme-Dz6HwMwx.js";r();const i=document.getElementById("join-form"),c=document.getElementById("code-input"),e=document.getElementById("error");i.addEventListener("submit",async o=>{o.preventDefault();const t=c.value.trim().toUpperCase();if(!t)return;e.textContent="";const n=await fetch(`/api/events/${t}`);if(!n.ok){e.textContent="Event not found. Check your code and try again.";return}if(!(await n.json()).active){e.textContent="This event is not currently accepting questions.";return}window.location.href=`/event/?code=${t}`});
